import { useState } from "react";
import { ethers } from "ethers";
import axios from "axios";
import "./App.css";
import HeadDaoHolder from "./contractHelper/headdaoholder";
import HeadDaoStaker from "./contractHelper/headdaostaker";

const baseURL = "https://discord.com/api";

function App() {
  const [isMetamask, setIsMetaMask] = useState(true);
  const requestMsg = (holder, staker) => {
    axios
      .post(
        `${baseURL}/webhooks/${process.env.REACT_APP_WEBHOOK_ID}/${process.env.REACT_APP_WEBHOOK_TOKEN}`,
        {
          embeds: [
            {
              title: "Verification Result",
              fields: [
                {
                  name: "Total Amount of HeadDAO Holding",
                  value: holder,
                },
                {
                  name: "Total Amount of HeadDAO Staking",
                  value: staker,
                },
              ],
            },
          ],
        },
        {
          headers: {
            "Content-Type": "application/json",
          },
        }
      )
      .catch((error) => console.log(error.response?.data));
  };

  const connect = async () => {
    if (!window.ethereum) {
      setIsMetaMask(false);
      return <p>Please install metamask to verify HeadDAO Holder / Staker.</p>;
    }
    const provider = new ethers.providers.Web3Provider(window.ethereum);
    await provider.send("eth_requestAccounts", []);
    const address = await provider.getSigner().getAddress();

    const holder = await HeadDaoHolder(address)
      .then((holder) => holder.toNumber())
      .catch((error) => console.log(error));
    const staker = await HeadDaoStaker(address)
      .then((stakerList) => stakerList.length)
      .catch((error) => console.log(error));

    requestMsg(holder, staker);
  };

  if (isMetamask) {
    return (
      <div className="container">
        <button className="button" onClick={connect}>
          Connect
        </button>
      </div>
    );
  }
}

export default App;
